+            state.mark_optimized();
+            state.record_verification(super::OptimizationEvidence {
+                fixtures_verified: 78,
+                mismatches: 0,
+                conformance_hash: "hash1".to_owned(),
+                verified_at_unix_ms: 2,
+            });
